mapper.select:
/* wms-master-robsortermgmt-sql-oracle.xml - selectRobsorterMgmtDuplicateCount */
SELECT COUNT(*)
  FROM TWORK_MST_ROBSORTER
 WHERE CTKEY = #{ctkey}
   AND ROBSORTERBOXNM = #{robsorterboxnm}

mapper.update:
/* wms-master-robsortermgmt-sql-oracle.xml - updateRobsorterMgmt */
UPDATE TWORK_MST_ROBSORTER
   SET WIDTH = COALESCE(#{width}, 0)
	 , DEPTH = COALESCE(#{depth}, 0)
	 , HEIGHT = COALESCE(#{height}, 0)
	 , CBMSTARTRNG = COALESCE(#{cbmstartrng}, 0)
	 , CBMCLOSRNG = COALESCE(#{cbmclosrng}, 0)
	 , USEYN = #{useyn}
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND ROBSORTERBOXNM = #{robsorterboxnm}

mapper.delete:
/* wms-master-robsortermgmt-sql-oracle.xml - deleteRobsorterMgmt */
DELETE
  FROM TWORK_MST_ROBSORTER
 WHERE CTKEY = #{ctkey}
   AND ROBSORTERBOXNM = #{robsorterboxnm}
